using System;
using System.Collections.Generic;
using Core.Master;
using Core.Update;
using Game.Block.Blocks.Fluid;
using Game.Block.Blocks.Machine.Inventory;
using Game.Block.Component;
using Game.Block.Interface;
using Game.Block.Interface.Component;
using Game.Block.Interface.State;
using Game.Fluid;
using MessagePack;
using Mooresmaster.Model.BlockConnectInfoModule;
using UniRx;

namespace Game.Block.Blocks.CleanRoom
{
    // VanillaMachineFluidInventoryComponent をコピーし、出力側を CleanRoomMachineOutputInventory に差し替えた専用版。
    // Copied from VanillaMachineFluidInventoryComponent; output side swapped to CleanRoomMachineOutputInventory.
    public class CleanRoomMachineFluidInventoryComponent : IFluidInventory, IUpdatableBlockComponent, IBlockStateObservable
    {
        private readonly VanillaMachineInputInventory _inputInventory;
        private readonly CleanRoomMachineOutputInventory _outputInventory;
        private readonly BlockConnectorComponent<IFluidInventory> _fluidConnector;
        private readonly Subject<Unit> _onChangeBlockState = new();

        public IObservable<Unit> OnChangeBlockState => _onChangeBlockState;

        public CleanRoomMachineFluidInventoryComponent(
            VanillaMachineInputInventory inputInventory,
            CleanRoomMachineOutputInventory outputInventory,
            BlockConnectorComponent<IFluidInventory> fluidConnector)
        {
            _inputInventory = inputInventory;
            _outputInventory = outputInventory;
            _fluidConnector = fluidConnector;
        }

        public void Update()
        {
            // 入力: パイプからの転送は AddLiquid で受動的に処理される
            // Input: pipe transfers are handled passively via AddLiquid

            // 出力: 機械からパイプへ流体を転送
            // Output: transfer fluid from the machine to pipes
            TransferFromMachineToPipes();

            // 入力タンクの送信元記録をクリア
            // Clear input-tank source records
            foreach (var container in _inputInventory.FluidInputSlot)
            {
                container.ClearPreviousSources();
                if (container.Amount <= 0) container.FluidId = FluidMaster.EmptyFluidId;
            }

            // 出力タンクの送信元記録をクリア
            // Clear output-tank source records
            foreach (var container in _outputInventory.FluidOutputSlot)
            {
                container.ClearPreviousSources();
                if (container.Amount <= 0) container.FluidId = FluidMaster.EmptyFluidId;
            }
        }

        private void TransferFromMachineToPipes()
        {
            // 接続されたパイプに流体を送る
            // Send fluid to connected pipes
            var connectedFluids = _fluidConnector.ConnectedTargets;
            foreach (var (fluidInventory, info) in connectedFluids)
            {
                // 自分側コネクタの ConnectTankIndex を取得
                // Get ConnectTankIndex from the self connector
                var tankIndex = -1;
                if (info.SelfConnector?.ConnectOption is FluidConnectOption selfOption)
                {
                    tankIndex = selfOption.ConnectTankIndex;
                }

                if (tankIndex < 0 || tankIndex >= _outputInventory.FluidOutputSlot.Count) continue;

                var container = _outputInventory.FluidOutputSlot[tankIndex];
                if (container.Amount <= 0) continue;

                // 流量制限を考慮して転送
                // Transfer with flow-rate limiting
                var flowRate = GetFlowRate(info);
                var transferAmount = Math.Min(container.Amount, flowRate * GameUpdater.SecondsPerTick);

                var fluidStack = new FluidStack(transferAmount, container.FluidId);
                var remaining = fluidInventory.AddLiquid(fluidStack, container);

                var transferred = transferAmount - remaining.Amount;
                if (transferred > 0)
                {
                    container.Amount -= transferred;
                    _onChangeBlockState.OnNext(Unit.Default);
                }

                if (container.Amount <= 0) container.FluidId = FluidMaster.EmptyFluidId;
            }
        }

        private double GetFlowRate(ConnectedInfo info)
        {
            if (info.SelfConnector?.ConnectOption is FluidConnectOption fluidOption)
            {
                return fluidOption.FlowCapacity;
            }
            throw new ArgumentException("FluidConnectOption is not set on connector");
        }

        public FluidStack AddLiquid(FluidStack fluidStack, FluidContainer source)
        {
            // 接続情報から ConnectTankIndex を取得する
            // Resolve the ConnectTankIndex from connection info
            var tankIndex = GetTargetTankIndexFromSource(source);

            // 特定タンクが指定されている場合はそのタンクのみに追加を試みる
            // If a tank is specified, add only to that tank
            if (tankIndex >= 0 && tankIndex < _inputInventory.FluidInputSlot.Count)
            {
                var container = _inputInventory.FluidInputSlot[tankIndex];
                if (container.FluidId == FluidMaster.EmptyFluidId || container.FluidId == fluidStack.FluidId)
                {
                    return container.AddLiquid(fluidStack, source);
                }
                return fluidStack;
            }

            // タンク未指定なら全入力タンクに追加を試みる
            // Otherwise try all input tanks
            foreach (var container in _inputInventory.FluidInputSlot)
            {
                if (container.FluidId != FluidMaster.EmptyFluidId && container.FluidId != fluidStack.FluidId) continue;

                var remaining = container.AddLiquid(fluidStack, source);
                if (remaining.Amount < fluidStack.Amount)
                {
                    _onChangeBlockState.OnNext(Unit.Default);
                    return remaining;
                }
            }

            return fluidStack;
        }

        private int GetTargetTankIndexFromSource(FluidContainer source)
        {
            // 接続先を調べて source がどの接続由来かを特定する
            // Inspect connections to find which one the source came from
            foreach (var (inventory, info) in _fluidConnector.ConnectedTargets)
            {
                if (inventory is FluidPipeComponent pipe)
                {
                    var pipeContainer = GetFluidContainerFromPipe(pipe);
                    if (pipeContainer == source)
                    {
                        if (info.TargetConnector?.ConnectOption is FluidConnectOption targetOption)
                        {
                            return targetOption.ConnectTankIndex;
                        }
                    }
                }
            }

            return -1;
        }

        private FluidContainer GetFluidContainerFromPipe(FluidPipeComponent pipe)
        {
            // リフレクションでプライベートフィールドにアクセス（Vanilla と同じ）
            // Access the private field via reflection (same as Vanilla)
            var field = typeof(FluidPipeComponent).GetField("_fluidContainer",
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            return field?.GetValue(pipe) as FluidContainer;
        }

        public List<FluidStack> GetFluidInventory()
        {
            var fluidStacks = new List<FluidStack>();

            foreach (var container in _inputInventory.FluidInputSlot)
            {
                if (container.Amount > 0) fluidStacks.Add(new FluidStack(container.Amount, container.FluidId));
            }

            foreach (var container in _outputInventory.FluidOutputSlot)
            {
                if (container.Amount > 0) fluidStacks.Add(new FluidStack(container.Amount, container.FluidId));
            }

            return fluidStacks;
        }

        public bool IsDestroy { get; private set; }

        public void Destroy()
        {
            IsDestroy = true;
            _onChangeBlockState?.Dispose();
        }

        public BlockStateDetail[] GetBlockStateDetails()
        {
            var inputTanks = new List<FluidMessagePack>();
            foreach (var container in _inputInventory.FluidInputSlot)
            {
                inputTanks.Add(new FluidMessagePack(container.FluidId, container.Amount, container.Capacity));
            }

            var outputTanks = new List<FluidMessagePack>();
            foreach (var container in _outputInventory.FluidOutputSlot)
            {
                outputTanks.Add(new FluidMessagePack(container.FluidId, container.Amount, container.Capacity));
            }

            var stateDetail = new FluidMachineInventoryStateDetail(inputTanks, outputTanks);
            var serialized = MessagePackSerializer.Serialize(stateDetail);

            return new[] { new BlockStateDetail(FluidMachineInventoryStateDetail.BlockStateDetailKey, serialized) };
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Core.Inventory;
using Core.Item.Interface;
using Core.Master;
using Core.Update;
using Game.Block.Blocks.Service;
using Game.Block.Component;
using Game.Block.Event;
using Game.Block.Interface;
using Game.Block.Interface.Component;
using Game.Block.Interface.Event;
using Game.Block.Blocks.Machine.Inventory;
using Game.Context;
using Game.Fluid;
using Mooresmaster.Model.MachineRecipesModule;
using UniRx;

namespace Game.Block.Blocks.CleanRoom
{
    // VanillaMachineOutputInventory をコピーして専用化。レベル付き出力は EUV→天井→down-bin 抽選で差し替え、空スロット予約で消失を防ぐ。
    // Copied from VanillaMachineOutputInventory; leveled outputs are drawn (EUV/ceiling/down-bin) and reserved by empty-slot count.
    public class CleanRoomMachineOutputInventory : IVanillaMachineSubInventory
    {
        public IReadOnlyList<IItemStack> OutputSlot => _itemDataStoreService.InventoryItems;
        IReadOnlyList<IItemStack> IVanillaMachineSubInventory.Items => OutputSlot;
        public IReadOnlyList<FluidContainer> FluidOutputSlot => _fluidContainers;

        private readonly BlockOpenableInventoryUpdateEvent _blockInventoryUpdate;
        private readonly ConnectingInventoryListPriorityInsertItemService _connectInventoryService;
        private readonly BlockInstanceId _blockInstanceId;
        private readonly CleanRoomStateReceiverComponent _receiver;

        // EUV失敗/Out で出力なしになったときに呼ぶテスト可視コールバック（サイレント消失アサート用）
        // Invoked when an EUV fail / Out yields no output (feeds the no-silent-loss assertion)
        private readonly Action _onNoOutputForTest;

        private readonly int _inputSlotSize;
        private readonly OpenableInventoryItemDataStoreService _itemDataStoreService;
        private readonly FluidContainer[] _fluidContainers;

        public CleanRoomMachineOutputInventory(int outputSlot, int outputTankCount, float innerTankCapacity, IItemStackFactory itemStackFactory,
            BlockOpenableInventoryUpdateEvent blockInventoryUpdate, BlockInstanceId blockInstanceId, int inputSlotSize, BlockConnectorComponent<IBlockInventory> blockConnectorComponent,
            CleanRoomStateReceiverComponent receiver, Action onNoOutputForTest)
        {
            _blockInventoryUpdate = blockInventoryUpdate;
            _blockInstanceId = blockInstanceId;
            _inputSlotSize = inputSlotSize;
            _receiver = receiver;
            _onNoOutputForTest = onNoOutputForTest;
            _itemDataStoreService = new OpenableInventoryItemDataStoreService(InvokeEvent, itemStackFactory, outputSlot);
            _connectInventoryService = new ConnectingInventoryListPriorityInsertItemService(blockInstanceId, blockConnectorComponent);

            _fluidContainers = new FluidContainer[outputTankCount];
            for (var i = 0; i < outputTankCount; i++)
            {
                _fluidContainers[i] = new FluidContainer(innerTankCapacity);
            }

            GameUpdater.UpdateObservable.Subscribe(_ => Update());
        }

        private void Update()
        {
            InsertConnectInventory();
        }

        // レベル付き出力は完了時 ItemId が down-bin/効果で変わり得るため空スロット方式で予約する
        // Leveled outputs reserve EMPTY slots because the final ItemId can change via down-bin / effect
        public bool IsAllowedToOutputItem(MachineRecipeMasterElement machineRecipe)
        {
            var leveledCount = 0;
            foreach (var itemOutput in machineRecipe.OutputItems)
            {
                if (MasterHolder.SemiconductorChipMaster.TryGetDistribution(machineRecipe.MachineRecipeGuid, itemOutput.ItemGuid, out _))
                {
                    leveledCount++;
                    continue;
                }

                // 非レベル出力は Vanilla と同じ判定（既存スタックへの追記も可）
                // Non-leveled outputs use the vanilla check (may append to an existing stack)
                var outputItemId = MasterHolder.ItemMaster.GetItemId(itemOutput.ItemGuid);
                var outputItemStack = ServerContext.ItemStackFactory.Create(outputItemId, itemOutput.Count);
                var isAllowed = OutputSlot.Aggregate(false, (current, slot) => slot.IsAllowedToAdd(outputItemStack) || current);
                if (!isAllowed) return false;
            }

            // 空スロット数 ≥ レベル付き出力要素数 を要求（MaxGrade 非依存）
            // Require empty slots >= leveled output count (independent of the current MaxGrade)
            if (leveledCount > 0)
            {
                var emptySlots = OutputSlot.Count(slot => slot.Id == ItemMaster.EmptyItemId);
                if (emptySlots < leveledCount) return false;
            }

            // 液体出力のスペースを確認する（Vanilla のコピー）
            // Check fluid output space (vanilla copy)
            for (var i = 0; i < machineRecipe.OutputFluids.Length; i++)
            {
                if (i >= _fluidContainers.Length) return false;

                var outputFluidId = MasterHolder.FluidMaster.GetFluidId(machineRecipe.OutputFluids[i].FluidGuid);
                var amount = machineRecipe.OutputFluids[i].Amount;

                if (_fluidContainers[i].FluidId != FluidMaster.EmptyFluidId && _fluidContainers[i].FluidId != outputFluidId) return false;
                if (_fluidContainers[i].Capacity - _fluidContainers[i].Amount < amount) return false;
            }

            return true;
        }

        // 出力要素単位で抽選して格納する（cycleSeed で決定的）
        // Emit outputs per element, drawing leveled ones deterministically from cycleSeed
        public void InsertOutputSlot(MachineRecipeMasterElement machineRecipe, long cycleSeed)
        {
            var effect = _receiver.CurrentEffect;

            for (var outputIndex = 0; outputIndex < machineRecipe.OutputItems.Length; outputIndex++)
            {
                var itemOutput = machineRecipe.OutputItems[outputIndex];

                ItemId outputItemId;
                var isLeveled = MasterHolder.SemiconductorChipMaster.TryGetDistribution(
                    machineRecipe.MachineRecipeGuid, itemOutput.ItemGuid, out _);
                if (isLeveled)
                {
                    // percent は EUV catastrophic 失敗率の補数（=成功率）。スキーマ default=1。
                    // percent is the complement of the EUV catastrophic failure rate (= success rate). schema default 1.
                    var percent = itemOutput.Percent;
                    var draw = SemiconductorChipDraw.TryResolveOutputItemId(
                        machineRecipe.MachineRecipeGuid, itemOutput.ItemGuid,
                        effect.MaxGrade, effect.DownBinRate, percent,
                        cycleSeed, outputIndex, out outputItemId);

                    if (draw != DrawResult.Drawn)
                    {
                        // EUV失敗/Out：出力なし（サイレント Lv1 禁止）。テストカウンタへ通知して何も出さない
                        // EUV fail / Out: no output (no silent Lv1). Notify the test counter and emit nothing
                        _onNoOutputForTest?.Invoke();
                        continue;
                    }
                }
                else
                {
                    // 副産物（分布なし）はベース ItemId のまま
                    // By-products keep their base ItemId
                    outputItemId = MasterHolder.ItemMaster.GetItemId(itemOutput.ItemGuid);
                }

                InsertToSlot(ServerContext.ItemStackFactory.Create(outputItemId, itemOutput.Count));
            }

            // 液体出力（Vanilla のコピー）
            // Fluid outputs (vanilla copy)
            for (var i = 0; i < machineRecipe.OutputFluids.Length; i++)
            {
                if (i >= _fluidContainers.Length) break;

                var fluidId = MasterHolder.FluidMaster.GetFluidId(machineRecipe.OutputFluids[i].FluidGuid);
                _fluidContainers[i].AddLiquid(new FluidStack(machineRecipe.OutputFluids[i].Amount, fluidId), FluidContainer.Empty);
            }
        }

        // 同 ItemId スロット→空スロットの順に1スタックを格納する
        // Insert a single stack into a matching-Id slot first, then an empty one
        private void InsertToSlot(IItemStack outputItemStack)
        {
            for (var i = 0; i < OutputSlot.Count; i++)
            {
                if (!OutputSlot[i].IsAllowedToAdd(outputItemStack)) continue;

                var item = OutputSlot[i].AddItem(outputItemStack).ProcessResultItemStack;
                _itemDataStoreService.SetItem(i, item);
                break;
            }
        }

        private void InsertConnectInventory()
        {
            for (var i = 0; i < OutputSlot.Count; i++)
                _itemDataStoreService.SetItem(i, _connectInventoryService.InsertItem(OutputSlot[i]));
        }

        public void SetItem(int slot, IItemStack itemStack)
        {
            _itemDataStoreService.SetItem(slot, itemStack);
        }

        public void SetItemWithoutEvent(int slot, IItemStack itemStack)
        {
            _itemDataStoreService.SetItemWithoutEvent(slot, itemStack);
        }

        private void InvokeEvent(int slot, IItemStack itemStack)
        {
            _blockInventoryUpdate.OnInventoryUpdateInvoke(new BlockOpenableInventoryUpdateEventProperties(
                _blockInstanceId, slot + _inputSlotSize, itemStack));
        }
    }
}

using System;
using System.Collections.Generic;
using Core.Update;
using Game.Block.Blocks.Machine;
using Game.Block.Blocks.Machine.Inventory;
using Game.Block.Blocks.Util;
using Game.Block.Interface;
using Game.Block.Interface.Component;
using Game.Block.Interface.State;
using Mooresmaster.Model.MachineRecipesModule;
using Newtonsoft.Json;
using UniRx;
using UnityEngine;

namespace Game.Block.Blocks.CleanRoom
{
    // VanillaMachineProcessorComponent をコピーして専用化。受信ゲートで開始/凍結を制御し、完了時に決定的 seed で抽選出力する。
    // Copied from VanillaMachineProcessorComponent; gates start/freeze on the receiver and emits via a deterministic cycle seed.
    public class CleanRoomMachineProcessorComponent : IBlockStateObservable, IUpdatableBlockComponent, ICleanRoomMachineRunningState
    {
        public Guid RecipeGuid => _processingRecipe?.MachineRecipeGuid ?? Guid.Empty;
        public float RequestPower => _requestPower;
        public ProcessState CurrentState { get; private set; }
        public uint RemainingTicks { get; private set; }

        // 稼働中（汚染中）判定。Processing 中は A_machine を部屋へ計上させる（凍結中も Processing 扱いだが部屋は Invalid なので影響しない）。
        // Running (polluting) when Processing; A_machine is booked while Processing (frozen stays Processing but the room is Invalid anyway).
        public bool IsRunning => CurrentState == ProcessState.Processing;

        // テスト可視カウンタ：出力インベントリから「出力なし（EUV失敗/Out）」通知を受けて加算する
        // Test-visible counter: incremented when the output inventory reports a no-output (EUV fail / Out)
        public int EuvFailCountForTest { get; private set; }

        public IObservable<Unit> OnChangeBlockState => _changeState;
        private readonly Subject<Unit> _changeState = new();

        private readonly VanillaMachineInputInventory _inputInventory;
        private readonly CleanRoomMachineOutputInventory _outputInventory;
        private readonly CleanRoomStateReceiverComponent _receiver;
        private readonly BlockInstanceId _blockInstanceId;
        private readonly float _requestPower;

        private MachineRecipeMasterElement _processingRecipe;
        private uint _processingRecipeTicks;
        private float _currentPower;
        private bool _usedPower;

        // セーブ対象：抽選の決定性をセーブ/ロード越しに保つためのサイクルカウンタ
        // Saved: deterministic-lottery cycle counter, persisted across save/load
        private uint _processedCycleCount;

        private ProcessState _lastState = ProcessState.Idle;

        // 新規作成
        // For new creation
        public CleanRoomMachineProcessorComponent(VanillaMachineInputInventory input, CleanRoomMachineOutputInventory output,
            CleanRoomStateReceiverComponent receiver, BlockInstanceId blockInstanceId, float requestPower)
            : this(input, output, receiver, blockInstanceId, requestPower, ProcessState.Idle, 0, null, 0)
        {
        }

        // セーブからの復元
        // For restoration from save
        public CleanRoomMachineProcessorComponent(VanillaMachineInputInventory input, CleanRoomMachineOutputInventory output,
            CleanRoomStateReceiverComponent receiver, BlockInstanceId blockInstanceId, float requestPower,
            ProcessState currentState, uint remainingTicks, MachineRecipeMasterElement processingRecipe, uint processedCycleCount)
        {
            _inputInventory = input;
            _outputInventory = output;
            _receiver = receiver;
            _blockInstanceId = blockInstanceId;
            _requestPower = requestPower;

            CurrentState = currentState;
            RemainingTicks = remainingTicks;
            _processingRecipe = processingRecipe;
            _processedCycleCount = processedCycleCount;
            if (processingRecipe != null) _processingRecipeTicks = GameUpdater.SecondsToTicks(processingRecipe.Time);
        }

        public void SupplyPower(float power)
        {
            BlockException.CheckDestroy(this);
            _usedPower = false;
            _currentPower = power;

            // アイドル中の給電はクライアントに伝わらないため明示通知する
            // Idle-time power supply isn't reflected to the client, so notify explicitly
            if (CurrentState == ProcessState.Idle) _changeState.OnNext(Unit.Default);
        }

        public void Update()
        {
            BlockException.CheckDestroy(this);
            if (_usedPower)
            {
                _usedPower = false;
                _currentPower = 0f;
            }

            // 状態ごとの処理
            // Per-state handling
            if (CurrentState == ProcessState.Idle) Idle();
            else Processing();

            // ステート変化時か処理中はイベントを発火
            // Fire the event on a state change or while processing
            if (_lastState != CurrentState || CurrentState == ProcessState.Processing)
            {
                _changeState.OnNext(Unit.Default);
                _lastState = CurrentState;
            }
        }

        private void Idle()
        {
            var isGetRecipe = _inputInventory.TryGetRecipeElement(out var recipe);

            // 受信値が InValidRoom=false（部屋外/Invalid/未プッシュ）なら開始しない
            // Do not start when the pushed effect says InValidRoom=false (outside / Invalid / not pushed)
            var roomAllowsStart = _receiver.CurrentEffect.InValidRoom;

            var isStartProcess = isGetRecipe && roomAllowsStart &&
                                 _inputInventory.IsAllowedToStartProcess() &&
                                 _outputInventory.IsAllowedToOutputItem(recipe);

            if (!isStartProcess) return;

            CurrentState = ProcessState.Processing;
            _processingRecipe = recipe;
            _processingRecipeTicks = GameUpdater.SecondsToTicks(_processingRecipe.Time);
            _inputInventory.ReduceInputSlot(_processingRecipe);
            RemainingTicks = _processingRecipeTicks;
        }

        private void Processing()
        {
            // 室が無効化されたら進捗を凍結する（Idle に落とさない・入出力も壊さない）。
            // 凍結中も _usedPower=true＝供給電力は消費される（意図的な仕様）。
            // Freeze progress while the room is invalid (stay Processing; nothing breaks).
            // _usedPower stays true: supplied power IS consumed while frozen (intentional).
            if (!_receiver.CurrentEffect.InValidRoom)
            {
                _usedPower = true;
                return;
            }

            var subTicks = MachineCurrentPowerToSubSecond.GetSubTicks(_currentPower, RequestPower);
            if (subTicks >= RemainingTicks)
            {
                RemainingTicks = 0;
                CurrentState = ProcessState.Idle;

                // サイクル完了：抽選 seed 用カウンタを前進させてから出力を確定する
                // Cycle complete: advance the deterministic cycle counter, then emit outputs
                _processedCycleCount++;
                _outputInventory.InsertOutputSlot(_processingRecipe, BuildCycleSeed());
            }
            else
            {
                RemainingTicks -= subTicks;
            }

            _usedPower = true;
        }

        // 決定的サイクル seed（自前カウンタ＋blockInstanceId。フェーズA非依存）
        // Deterministic per-cycle seed from our own counter + blockInstanceId (phase-A independent)
        private long BuildCycleSeed()
        {
            return ((long)_blockInstanceId.AsPrimitive() << 20) ^ (long)_processedCycleCount;
        }

        // 出力インベントリが出力なし（EUV失敗/Out）を報告したときに加算する
        // Increment when the output inventory reports a no-output (EUV fail / Out)
        public void NotifyNoOutput()
        {
            EuvFailCountForTest++;
        }

        public BlockStateDetail[] GetBlockStateDetails()
        {
            BlockException.CheckDestroy(this);

            var processingRate = Mathf.Clamp01(_processingRecipeTicks > 0 ? 1f - (float)RemainingTicks / _processingRecipeTicks : 0f);
            var commonMachineBlock = CommonMachineBlockStateDetail.CreateState(_currentPower, RequestPower, processingRate, CurrentState.ToStr(), _lastState.ToStr());
            var machineBlock = MachineBlockStateDetail.CreateState(processingRate, RecipeGuid);
            return new[] { commonMachineBlock, machineBlock };
        }

        public bool IsDestroy { get; private set; }
        public void Destroy()
        {
            IsDestroy = true;
        }

        // セーブデータ構築（_processedCycleCount を追加で永続化）
        // Build save data (also persists _processedCycleCount)
        public CleanRoomMachineProcessorSaveJsonObject GetSaveJsonObject()
        {
            BlockException.CheckDestroy(this);
            return new CleanRoomMachineProcessorSaveJsonObject
            {
                State = (int)CurrentState,
                RemainingSeconds = GameUpdater.TicksToSeconds(RemainingTicks),
                RecipeGuidStr = RecipeGuid.ToString(),
                ProcessedCycleCount = _processedCycleCount,
            };
        }
    }

    public class CleanRoomMachineProcessorSaveJsonObject
    {
        [JsonProperty("state")]
        public int State;

        [JsonProperty("remainingSeconds")]
        public double RemainingSeconds;

        [JsonProperty("recipeGuid")]
        public string RecipeGuidStr;

        [JsonIgnore]
        public Guid RecipeGuid => Guid.Parse(RecipeGuidStr);

        // 抽選の決定性を保つサイクルカウンタ
        // Cycle counter that keeps the lottery deterministic
        [JsonProperty("processedCycleCount")]
        public uint ProcessedCycleCount;
    }
}

