namespace Game.Block.Factory.BlockTemplate
{
    // VanillaMachineTemplate をコピーし、専用コンポーネント＋CleanRoomStateReceiverComponent を合成する（blockType CleanRoomMachine 用）。
    // Copied from VanillaMachineTemplate; composes the dedicated components + CleanRoomStateReceiverComponent for blockType CleanRoomMachine.
    public class VanillaCleanRoomMachineTemplate : IBlockTemplate
    {
        private readonly BlockOpenableInventoryUpdateEvent _blockInventoryUpdateEvent;

        public VanillaCleanRoomMachineTemplate(BlockOpenableInventoryUpdateEvent blockInventoryUpdateEvent)
        {
            _blockInventoryUpdateEvent = blockInventoryUpdateEvent;
        }

        public IBlock New(BlockMasterElement blockMasterElement, BlockInstanceId blockInstanceId, BlockPositionInfo blockPositionInfo, BlockCreateParam[] createParams)
        {
            return GetBlock(null, blockMasterElement, blockInstanceId, blockPositionInfo);
        }

        public IBlock Load(Dictionary<string, string> componentStates, BlockMasterElement blockMasterElement, BlockInstanceId blockInstanceId, BlockPositionInfo blockPositionInfo)
        {
            return GetBlock(componentStates, blockMasterElement, blockInstanceId, blockPositionInfo);
        }

        private IBlock GetBlock(Dictionary<string, string> componentStates, BlockMasterElement blockMasterElement, BlockInstanceId blockInstanceId, BlockPositionInfo blockPositionInfo)
        {
            var machineParam = blockMasterElement.BlockParam as CleanRoomMachineBlockParam;

            BlockConnectorComponent<IBlockInventory> inventoryConnectorComponent = BlockTemplateUtil.CreateInventoryConnector(machineParam.InventoryConnectors, blockPositionInfo);

            var blockId = MasterHolder.BlockMaster.GetBlockId(blockMasterElement.BlockGuid);

            // 受信ゲートを先に作る（出力インベントリが効果値を参照するため）
            // Build the receiver first because the output inventory references its effect values
            var receiver = new CleanRoomStateReceiverComponent();

            // 流体タンク容量はマスタ値を使う（Vanillaと同じ）
            // Use master values for fluid tank counts/capacity (same as Vanilla)
            var inputTankCount = machineParam.InputTankCount;
            var outputTankCount = machineParam.OutputTankCount;
            var innerTankCapacity = machineParam.InnerTankCapacity;

            // 入力とモジュールは Vanilla を再利用、出力は専用型を組む
            // Reuse Vanilla input/module; build the dedicated output inventory
            var input = new VanillaMachineInputInventory(
                blockId, machineParam.InputSlotCount, inputTankCount, innerTankCapacity,
                _blockInventoryUpdateEvent, blockInstanceId,
                ServerContext.GetService<IGameUnlockStateDataController>());

            // 出力なし通知をプロセッサへ橋渡しする（プロセッサは後で生成するため遅延束縛）
            // Forward the no-output notification to the processor (bound lazily; processor is created later)
            CleanRoomMachineProcessorComponent processorRef = null;

            var output = new CleanRoomMachineOutputInventory(
                machineParam.OutputSlotCount, outputTankCount, innerTankCapacity, ServerContext.ItemStackFactory,
                _blockInventoryUpdateEvent, blockInstanceId, machineParam.InputSlotCount,
                inventoryConnectorComponent, receiver, () => processorRef?.NotifyNoOutput());

            var module = new VanillaMachineModuleInventory(
                machineParam.ModuleSlotCount, _blockInventoryUpdateEvent, blockInstanceId,
                machineParam.InputSlotCount, machineParam.OutputSlotCount);

            var requestPower = machineParam.RequiredPower;

            // 新規作成またはセーブから復元
            // Create new or restore from save
            var processor = componentStates == null
                ? new CleanRoomMachineProcessorComponent(input, output, receiver, blockInstanceId, requestPower)
                : LoadProcessor(componentStates, input, output, module, receiver, blockInstanceId, requestPower);
            processorRef = processor;

            var blockInventory = new CleanRoomMachineBlockInventoryComponent(input, output, module);
            var machineSave = new CleanRoomMachineSaveComponent(input, output, module, processor);
            var electric = new CleanRoomMachineElectricComponent(blockInstanceId, processor);

            var components = new List<IBlockComponent>
            {
                blockInventory,
                machineSave,
                processor,
                electric,
                receiver,
                inventoryConnectorComponent,
            };

            // 流体接続のサポートを追加（流体インベントリコネクタが定義されている場合・Vanillaのコピー）
            // Add fluid connection support when fluid connectors are defined (mirrors Vanilla)
            if (machineParam.FluidInventoryConnectors != null && (inputTankCount > 0 || outputTankCount > 0))
            {
                var fluidConnector = IFluidInventory.CreateFluidInventoryConnector(machineParam.FluidInventoryConnectors, blockPositionInfo);
                var fluidInventory = new CleanRoomMachineFluidInventoryComponent(input, output, fluidConnector);

                components.Add(fluidConnector);
                components.Add(fluidInventory);
            }

            return new BlockSystem(blockInstanceId, blockMasterElement.BlockGuid, components, blockPositionInfo);
        }

        // セーブから入出力・加工状態を復元する（VanillaのMachineLoadState を専用型向けに移植）
        // Restore inventory and processing state from save (ported from MachineLoadState for the dedicated types)
        private CleanRoomMachineProcessorComponent LoadProcessor(
            Dictionary<string, string> componentStates,
            VanillaMachineInputInventory input, CleanRoomMachineOutputInventory output, VanillaMachineModuleInventory module,
            CleanRoomStateReceiverComponent receiver, BlockInstanceId blockInstanceId, float requestPower)
        {
            var state = componentStates[CleanRoomMachineSaveComponent.SaveKeyStatic];
            var jsonObject = JsonConvert.DeserializeObject<CleanRoomMachineJsonObject>(state);

            var inputItems = jsonObject.InputSlot.Select(item => item.ToItemStack()).ToList();
            for (var i = 0; i < inputItems.Count && i < input.InputSlot.Count; i++) input.SetItemWithoutEvent(i, inputItems[i]);

            var outputItems = jsonObject.OutputSlot.Select(item => item.ToItemStack()).ToList();
            for (var i = 0; i < outputItems.Count && i < output.OutputSlot.Count; i++) output.SetItemWithoutEvent(i, outputItems[i]);

            if (jsonObject.ModuleSlot != null)
            {
                var moduleItems = jsonObject.ModuleSlot.Select(item => item.ToItemStack()).ToList();
                for (var i = 0; i < moduleItems.Count && i < module.ModuleSlot.Count; i++) module.SetItemWithoutEvent(i, moduleItems[i]);
            }

            // 流体タンクを復元（Vanilla の MachineLoadState と同じ）
            // Restore fluid tanks (same as Vanilla MachineLoadState)
            if (jsonObject.InputFluidSlot != null)
            {
                for (var i = 0; i < jsonObject.InputFluidSlot.Count && i < input.FluidInputSlot.Count; i++)
                {
                    var fluidData = jsonObject.InputFluidSlot[i];
                    input.FluidInputSlot[i].FluidId = fluidData.FluidId;
                    input.FluidInputSlot[i].Amount = fluidData.Amount;
                }
            }

            if (jsonObject.OutputFluidSlot != null)
            {
                for (var i = 0; i < jsonObject.OutputFluidSlot.Count && i < output.FluidOutputSlot.Count; i++)
                {
                    var fluidData = jsonObject.OutputFluidSlot[i];
                    output.FluidOutputSlot[i].FluidId = fluidData.FluidId;
                    output.FluidOutputSlot[i].Amount = fluidData.Amount;
                }
            }

            var processorJson = jsonObject.Processor;
            var recipe = processorJson.RecipeGuid == Guid.Empty ? null : MasterHolder.MachineRecipesMaster.GetRecipeElement(processorJson.RecipeGuid);
            var remainingTicks = GameUpdater.SecondsToTicks(processorJson.RemainingSeconds);

            return new CleanRoomMachineProcessorComponent(
                input, output, receiver, blockInstanceId, requestPower,
                (Game.Block.Blocks.Machine.ProcessState)processorJson.State, remainingTicks, recipe, processorJson.ProcessedCycleCount);
        }
    }
}

using System.Collections.Generic;
using Mooresmaster.Loader.CleanRoomThresholdsModule;
using Mooresmaster.Model.CleanRoomThresholdsModule;
using Newtonsoft.Json.Linq;

namespace Core.Master
{
    // クリーンルーム閾値テーブル。行0が最良、行数=Out。
    // Clean room threshold table; row 0 is cleanest, row count means Out.
    public class CleanRoomThresholdMaster : IMasterValidator
    {
        public readonly CleanRoomThresholds CleanRoomThresholds;

        // 行0が最良（A相当）。行数がOutのインデックス。
        // Row 0 is cleanest (class A); row count is the Out threshold index.
        public IReadOnlyList<CleanRoomThresholdMasterElement> Rows => CleanRoomThresholds.Data;
        public int OutThresholdIndex => Rows.Count;

        public CleanRoomThresholdMaster(JToken jToken)
        {
            CleanRoomThresholds = CleanRoomThresholdsLoader.Load(jToken);
        }

        public bool Validate(out string errorLogs)
        {
            // 行が空だと閾値判定・Out インデックスが成立しない。
            // An empty table makes threshold decisions and the Out index meaningless.
            if (Rows.Count == 0)
            {
                errorLogs = "cleanRoomThresholds must have at least one row";
                return false;
            }

            // 各行の値域を確認（DownBinRate は確率、MaxGrade は非負グレード）。
            // Validate per-row ranges (DownBinRate is a probability, MaxGrade is a non-negative grade).
            for (var i = 0; i < Rows.Count; i++)
            {
                if (Rows[i].DownBinRate < 0 || Rows[i].DownBinRate > 1)
                {
                    errorLogs = $"cleanRoomThresholds downBinRate must be in [0,1] but was {Rows[i].DownBinRate}. row={i}";
                    return false;
                }
                if (Rows[i].MaxGrade < 0)
                {
                    errorLogs = $"cleanRoomThresholds maxGrade must be >= 0 but was {Rows[i].MaxGrade}. row={i}";
                    return false;
                }
            }

            // 行の単調性（濃度昇順・必要換気降順）を強制。ヒステリシス判定の前提。
            // Enforce monotonic rows (concentration asc, required ACH desc); hysteresis relies on this.
            for (var i = 1; i < Rows.Count; i++)
            {
                if (Rows[i].MaxConcentration <= Rows[i - 1].MaxConcentration ||
                    Rows[i].RequiredAirChangeRate >= Rows[i - 1].RequiredAirChangeRate)
                {
                    errorLogs = $"cleanRoomThresholds rows must be sorted (cleanest first). row={i}";
                    return false;
                }
            }

            errorLogs = null;
            return true;
        }

        public void Initialize() { }
    }
}

using System;
using System.Collections.Generic;
using Mooresmaster.Loader.SemiconductorChipsModule;
using Mooresmaster.Model.SemiconductorChipsModule;
using Newtonsoft.Json.Linq;

namespace Core.Master
{
    // 半導体チップ Lv↔ItemId 対応とレシピ出力要素単位のレベル分布を管理。
    // Manages semiconductor chip Lv<->ItemId mapping and per-output-element level distributions.
    public class SemiconductorChipMaster : IMasterValidator
    {
        private readonly SemiconductorChips _data;

        // Lv→ItemId の正引きテーブル（ロード時1回構築）。
        // Forward lookup table Lv->ItemId, built once on load.
        private Dictionary<int, ItemId> _levelToItemId;

        // ItemId→Lv の逆引きテーブル（チップ判定用）。
        // Reverse lookup table ItemId->Lv (for chip detection).
        private Dictionary<ItemId, int> _itemIdToLevel;

        // (machineRecipeGuid, outputItemGuid) → levelWeights の分布テーブル。
        // Distribution table keyed by (machineRecipeGuid, outputItemGuid).
        private Dictionary<(Guid, Guid), IReadOnlyList<(int level, double weight)>> _distributions;

        public SemiconductorChipMaster(JToken jToken)
        {
            _data = SemiconductorChipsLoader.Load(jToken);
        }

        // チップ Lv から ItemId を解決する。Lv が存在しない場合は KeyNotFoundException を投げる。
        // Resolve ItemId from chip level; throws KeyNotFoundException if level is absent.
        public ItemId GetChipItemId(int level)
        {
            return _levelToItemId[level];
        }

        // ItemId からチップ Lv を逆引きする。チップでなければ -1 を返す。
        // Reverse-lookup chip level from ItemId; returns -1 if not a chip.
        public int GetChipLevel(ItemId itemId)
        {
            return _itemIdToLevel.TryGetValue(itemId, out var lv) ? lv : -1;
        }

        // レシピ出力要素の分布を取得する。level 昇順にソートして返す。分布が無ければ false。
        // Get distribution for a recipe output element, sorted ascending by level. Returns false if absent.
        public bool TryGetDistribution(Guid machineRecipeGuid, Guid outputItemGuid, out IReadOnlyList<(int level, double weight)> dist)
        {
            return _distributions.TryGetValue((machineRecipeGuid, outputItemGuid), out dist);
        }

        public bool Validate(out string errorLogs)
        {
            // chipLevels が空でなく、level/itemGuid が重複しないことを確認。
            // Ensure chipLevels is non-empty and has distinct level/itemGuid.
            if (_data.ChipLevels.Length == 0)
            {
                errorLogs = "semiconductorChips: chipLevels must not be empty";
                return false;
            }

            var seenLevels = new HashSet<int>();
            var seenGuids = new HashSet<Guid>();
            foreach (var chip in _data.ChipLevels)
            {
                if (!seenLevels.Add(chip.Level))
                {
                    errorLogs = $"semiconductorChips: duplicate level {chip.Level}";
                    return false;
                }
                if (!seenGuids.Add(chip.ItemGuid))
                {
                    errorLogs = $"semiconductorChips: duplicate itemGuid {chip.ItemGuid}";
                    return false;
                }
            }

            // 分布キー (machineRecipeGuid, outputItemGuid) の重複検出用。
            // Tracks distribution keys (machineRecipeGuid, outputItemGuid) to detect duplicates.
            var seenDistKeys = new HashSet<(Guid, Guid)>();
            foreach (var dist in _data.OutputDistributions)
            {
                // levelWeights が空だと分布として成立しない。
                // An empty levelWeights cannot form a distribution.
                if (dist.LevelWeights.Length == 0)
                {
                    errorLogs = $"semiconductorChips: outputDistributions entry has empty levelWeights (recipe={dist.MachineRecipeGuid})";
                    return false;
                }

                // 分布キー重複はルックアップが曖昧になるため禁止。
                // Duplicate distribution keys make lookups ambiguous; reject them.
                if (!seenDistKeys.Add((dist.MachineRecipeGuid, dist.OutputItemGuid)))
                {
                    errorLogs = $"semiconductorChips: duplicate distribution key (recipe={dist.MachineRecipeGuid}, output={dist.OutputItemGuid})";
                    return false;
                }

                // 各 levelWeight の level は chipLevels に存在し、weight は正でなければならない。
                // Each levelWeight's level must exist in chipLevels and weight must be positive.
                foreach (var lw in dist.LevelWeights)
                {
                    if (!seenLevels.Contains(lw.Level))
                    {
                        errorLogs = $"semiconductorChips: levelWeights references unknown level {lw.Level} (recipe={dist.MachineRecipeGuid}, output={dist.OutputItemGuid})";
                        return false;
                    }
                    if (lw.Weight <= 0)
                    {
                        errorLogs = $"semiconductorChips: levelWeights weight must be > 0 but was {lw.Weight} (level={lw.Level}, recipe={dist.MachineRecipeGuid})";
                        return false;
                    }
                }
            }

            errorLogs = null;
            return true;
        }

        public void Initialize()
        {
            // Lv↔ItemId テーブルを構築する。
            // Build Lv<->ItemId tables.
            _levelToItemId = new Dictionary<int, ItemId>(_data.ChipLevels.Length);
            _itemIdToLevel = new Dictionary<ItemId, int>(_data.ChipLevels.Length);
            foreach (var chip in _data.ChipLevels)
            {
                var itemId = MasterHolder.ItemMaster.GetItemId(chip.ItemGuid);
                _levelToItemId[chip.Level] = itemId;
                _itemIdToLevel[itemId] = chip.Level;
            }

            // 分布テーブルを level 昇順ソートで構築する。
            // Build distribution table with per-entry list sorted ascending by level.
            _distributions = new Dictionary<(Guid, Guid), IReadOnlyList<(int level, double weight)>>(_data.OutputDistributions.Length);
            foreach (var dist in _data.OutputDistributions)
            {
                var weights = new List<(int level, double weight)>(dist.LevelWeights.Length);
                foreach (var lw in dist.LevelWeights)
                    weights.Add((lw.Level, lw.Weight));

                // level 昇順ソート（Task 1 の DrawBaseLevel が前提とする順序）。
                // Sort ascending by level (required by Task 1's DrawBaseLevel).
                weights.Sort((a, b) => a.level.CompareTo(b.level));

                _distributions[(dist.MachineRecipeGuid, dist.OutputItemGuid)] = weights;
            }
        }
    }
}

