            ServerContext.WorldBlockDatastore.TryAddBlock(ForUnitTestModBlockId.CleanRoomWallId,
                new Vector3Int(2, 2, 0), BlockDirection.North, System.Array.Empty<BlockCreateParam>(), out _);
