            compA.AddLiquid(new global::Game.Fluid.FluidStack(40.0, fluidId), global::Game.Fluid.FluidContainer.Empty);
            // 接続先なし・tickも進めない → 内部コンテナに 40 が残ったまま
            // No target, no ticks → 40 stays in the inner container

